import type { Quiz } from "../quiz-types.js";

export const week4Quizzes: Quiz[] = [
  {
    id: "day11", day: "Day 11", title: "Forecasting (including Services)", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "Every AE is responsible for forecasting their business. How often is the current quarter forecast submitted, and when is the next quarter forecast reviewed?", options: ["Both current and next quarter forecasts are submitted weekly — the cadence ensures leadership has rolling visibility into both near-term and forward-looking pipeline on the same review cycle", "Current quarter forecast is submitted weekly; next quarter forecast is reviewed the first week of each month", "Current quarter forecast is submitted bi-weekly; next quarter forecast is submitted at the start of each quarter — this lighter cadence prevents forecast fatigue while still maintaining adequate visibility for planning", "Forecasts are submitted on demand when your FLM requests them — Amplitude keeps the process flexible so AEs can focus on selling rather than forecast administration"], correct: 1, explanation: "Per the forecasting deck: AEs submit a current quarter forecast every week, broken down by month. Next quarter forecast is reviewed the first week of each month. Every AE has a weekly meeting with management to discuss their Commit (forecast) and which deals are included. This cadence connects to the weekly forecasting process: AEs update opportunities and submit on Monday/Tuesday; FLMs review and submit Wednesday; VPs and CRO review Thursday; President review happens Friday.", resource: { label: "Forecasting Slides — Forecast Schedule (Weekly Current Quarter, Monthly Next Quarter)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "What are the four forecast categories for new business, from most conservative to most aggressive?", options: ["Closed, Commit, Strong Upside, Upside", "Worst Case, Commit, Best Case, Stretch — this naming convention signals confidence levels from conservative to aggressive, helping leadership understand the range of possible outcomes each quarter", "Closed Won, Commit, Upside, Pipeline — categories map directly to SFDC stages so the forecast pulls automatically from opportunity data without manual category assignment", "Conservative, Realistic, Optimistic, Stretch — this labeling mirrors how Finance models revenue scenarios for board reporting and investor communications"], correct: 0, explanation: "The four new business forecast categories are: Closed Won (already booked), Commit (deals you're committing will close this period — your 'most likely' number), Strong Upside (deals with good probability but not fully committed), and Upside (possible but less certain). Your Worst Case forecast = Closed Won + Commit + some Strong Upside. Your full Commit = Closed Won + Commit + some Strong Upside + some Upside. Knowing these definitions is essential for having credible forecast conversations with your FLM.", resource: { label: "Forecasting Slides — New Business Forecasting: Worst Case, Commit, Goal, Best Case", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "Your FLM asks for your Worst Case forecast number. You have $50K Closed Won, $80K in Commit, $40K Strong Upside, and $30K Upside. What should your Worst Case be?", options: ["$50K — Worst Case is only Closed Won, representing the absolute floor of committed revenue that has already been executed and can't fall out of the forecast under any circumstance", "$130K — Worst Case is Closed Won + Commit, reflecting only deals with signed agreements or verbal commitments from the economic buyer that give you near-certain confidence in booking", "Between $150K–$170K — Worst Case is Closed Won + Commit + some Strong Upside", "$200K — Worst Case is everything you could possibly close, because showing the full upside number gives leadership maximum visibility into the quarter's total potential"], correct: 2, explanation: "Worst Case = Closed Won + Commit + some Strong Upside. In this example: $50K (CW) + $80K (Commit) = $130K as the base. Adding 'some' Strong Upside from the $40K pool puts Worst Case in the $150K–$170K range depending on deal specifics. Worst Case is defined as the 'realistic worst case or minimum amount you will close by end of the period, irrespective of unforeseen headwinds.' It's not just CW — and it's not everything including pure Upside. The precision of this number is what makes you credible with leadership.", resource: { label: "Forecasting Slides — New Business Forecasting: Forecast Category Definitions", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 4, type: "mc", lo: "LO3", text: "An AE moves a deal from Upside to Commit in Salesforce on Monday but doesn't update the opportunity's close date, stage, or last activity. Their FLM reviews it Wednesday. What problem does this create?", options: ["No problem — changing the forecast category is sufficient for the FLM to review accurately, since the category itself communicates the AE's confidence level and judgment about the deal's likelihood to close", "The FLM will move the deal back to Upside — forecast categories must match deal stage, and any mismatch between the two fields triggers an automatic system flag that blocks the weekly submission", "The forecast category change creates a mismatch: the AE claims Commit but the opportunity shows stale close date, wrong stage, no recent activity. A forecast without SFDC evidence can't be trusted or reviewed at VP/CRO level.", "Nothing — the FLM will add the missing information after the forecast review call, since FLMs are responsible for ensuring opportunity hygiene before submitting the consolidated team forecast upstream"], correct: 2, explanation: "Forecasting at Amplitude requires SFDC evidence to support the forecast claim. Per the forecasting deck, 'SF/Outreach reviewed for completeness → Submit Forecasts' is a pre-submission requirement at every level of the cadence. A deal in Commit must have: updated close date, correct stage, recent activity logged, and a clear MEDDPICC picture. Without it, the FLM has no basis to pass the forecast up the chain — and when leadership reviews larger deals on Friday, discrepancies between claimed Commit and SFDC evidence damage the AE's credibility.", resource: { label: "Forecasting Slides — Weekly Forecasting Process (SF/Outreach Reviewed for Completeness)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 5, type: "tf", lo: "LO1", text: "True or False: Services (PS and PSP) are included in the same forecast as New Business and Renewals.", options: ["True", "False"], correct: 1, explanation: "There are three distinct forecast types: New Business, Renewals, and Services. Services forecasting exists because PS and PSP revenue is recognized differently, requires separate capacity planning for PS staffing, and is tracked independently for business visibility. AEs are responsible for all three — forecasting a deal without its associated Services component creates blind spots for the PS team. When attaching implementation to a deal, ensure the Services component is forecasted alongside the subscription ARR.", resource: { label: "Forecasting Slides — Types of Forecasts (New Business, Renewals, Services)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "You're in a Wednesday meeting with your FLM for your weekly forecast review. They push back on a deal you have in Commit: 'I don't see the Economic Buyer engaged, no MAP in the SFDC notes, and the close date hasn't changed in 3 weeks.' Applying the CEM and forecasting standards, is your FLM right to push back?", options: ["No — the AE's judgment on deal stage and forecast category is the primary signal, and FLMs should defer to AE conviction when the rep has direct relationship context that isn't reflected in SFDC fields", "Yes. At S2+, MEDDPICC must be populated including EB confirmed. MAP required at S3+. A stale close date with no activity signals a stalled deal. The FLM is using SFDC evidence to pressure-test claims.", "No — a deal can be in Commit without EB engagement as long as the Champion is actively working it and has provided verbal confirmation that the economic buyer supports the initiative internally", "Yes, but only for deals over $100K — smaller deals can stay in Commit with less SFDC evidence since the risk exposure on sub-$100K deals doesn't warrant the same level of forecast rigor from leadership"], correct: 1, explanation: "This is what a good FLM review looks like. Per the CEM, Economic Buyer engagement is required at S2 exit. A MAP is required at S3+ for deals over $100K. A stale close date with no activity is a red flag, not a forecasting artifact. Moving a deal to Commit without SFDC evidence to support it is the most common forecasting mistake AEs make — it inflates the number, destroys credibility with leadership, and masks deal risk that should be addressed. The FLM's job is to ensure the forecast reflects reality, not aspiration.", resource: { label: "Customer Engagement Model — S2 Qualification Exit Criteria (MEDDPICC + EB Confirmed)", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 7, type: "mc", lo: "LO1", text: "The weekly forecasting cadence runs Monday through Friday with activities at each level. On what day does the AE's primary responsibility occur?", options: ["Friday — AEs submit their forecast at the end of the week so leadership has the most current data going into the weekend planning cycle and Monday pipeline reviews", "Wednesday — AEs update opportunities and submit forecasts before the FLM review call, ensuring the FLM has same-day data for the mid-week checkpoint with VP leadership", "Monday and Tuesday — AEs update opportunities and submit forecasts before the Wednesday FLM call", "Thursday — AEs update before the VP call, giving VPs real-time opportunity data for the Friday CRO and President forecast reviews"], correct: 2, explanation: "Per the weekly forecasting process: AEs update opportunities and submit forecasts on Monday and Tuesday. This feeds the FLM review (which includes AEs and CSMs) on Wednesday. The FLM then submits to the VP, who reviews Thursday. The VP submits to the CRO, who reviews Friday. The President Forecast Call is also Friday. The entire chain depends on AEs updating SFDC and submitting forecasts on Monday/Tuesday — anything later breaks the cadence and leaves FLMs working with stale data.", resource: { label: "Forecasting Slides — Weekly Forecasting Process (AEs Update Mon/Tue)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The Amplitude tool that delivers AI-generated deal updates, call summaries, and opportunity field recommendations directly into Slack — reducing manual SFDC updates for AEs — is called ________.", correct: ["Momentum", "momentum"], placeholder: "tool name...", explanation: "Momentum is the conversation intelligence platform that converts call insights into deal updates, delivering them into Slack DMs, account channels, and SFDC opportunity records. In the context of forecasting, Momentum reduces the manual burden of keeping SFDC current — which is the prerequisite for accurate forecasting. If SFDC is stale, the forecast is stale. Momentum's Phase 1 covers AEs and SDRs; Phase 2 extends to post-sales and renewals.", resource: { label: "Momentum (for Slack) Deck — Executive Summary (What It Is)", url: "https://docs.google.com/presentation/d/129YPTu9OKQYZM6fFIMxlsJOqalqUWcwlLvLnC4lOvXI/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "An AE has a deal at S4 (Proof of Value) with $200K subscription ARR and $40K in PSP Advanced attached. When forecasting this deal, how should the Services component be handled?", options: ["Include PSP in the subscription ARR number — it's part of the deal total and should be reflected in a single New Business forecast line to give leadership a complete view of each opportunity's value", "Ignore PSP in forecasting — Services are tracked separately by the PS team, and AEs don't have visibility into PS capacity or delivery scheduling to forecast services accurately", "Forecast Services ($40K PSP + implementation) separately in the Services forecast, and the $200K subscription ARR in New Business. Both must be submitted.", "Forecast only the ARR; Services are tracked by Finance at close — the Finance team reconciles services revenue post-booking using the PS team's delivery records and contract attachments"], correct: 2, explanation: "Services must be forecasted in the Services category — separately from subscription ARR in the New Business category. AEs are responsible for all three forecast types: New Business, Renewals, and Services. Forecasting $200K in New Business without the associated Services component creates a blind spot for PS capacity planning and Financial forecasting. The PS team uses Services forecasts to staff engagements — a Services number that appears at close without prior forecasting creates implementation delays that hurt TTF and adoption.", resource: { label: "Forecasting Slides — Services Forecasting (Must Be Forecast Separately)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "Why does Amplitude's leadership invest heavily in the forecasting cadence — weekly calls up through the President level? What are the stated business reasons?", options: ["To monitor individual AE performance and identify underperformers early — the weekly cadence gives management a real-time view of which reps are tracking to quota and which need intervention or coaching support", "To satisfy investor reporting requirements for a public company — as a publicly traded company, Amplitude has SEC reporting obligations that require accurate forward-looking revenue projections each quarter", "Four reasons: headcount planning, risk mitigation, business predictability (leadership/board/investors), and a dedicated forum for deal discussion, coaching, and unblocking.", "To ensure accurate commission calculations at the end of each quarter — forecast data feeds directly into the compensation engine, and discrepancies between forecast and actuals create payment disputes and SPIFs issues"], correct: 2, explanation: "Per the forecasting deck, the four business reasons for forecasting are: Headcount Planning (expected revenue drives decisions on SE, CS, and PS hiring), Risk Mitigation (greater revenue outlook enables earlier identification of business risks), Business Predictability (investment decisions and communications to leadership/board/investors), and Forum for Deal Discussion (dedicated time for deal status, risks, and coaching). Understanding why forecasting matters — not just how to do it — helps AEs take it seriously as a business contribution, not just a compliance activity.", resource: { label: "Forecasting Slides — Why Do We Forecast? (4 Business Reasons)", url: "https://docs.google.com/presentation/d/19-B_1a-oBmuMoI_4lc1L5W1oiZZN6pXALYMZObBc9L8/edit" } },
    ],
  },
  {
    id: "day12", day: "Day 12", title: "Customer Stories", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "Where do you go to find curated, approved customer stories organized by industry and use case?", options: ["Google Drive — search for 'customer stories' to find the most recent decks, since the marketing team maintains a shared folder with the latest approved versions organized by quarter and region", "Highspot — the Customer Stories hub, organized by industry, use case, and value driver", "Amplitude's public website — all customer case studies are publicly available and always current, so any story on the website is pre-approved for external use in prospect conversations", "Glean — search for customer name + 'case study' to find the most relevant story, since Glean indexes across all internal systems and surfaces the most recently updated version automatically"], correct: 1, explanation: "Highspot is the authoritative source for customer stories at Amplitude. It's organized by industry, use case, and value driver — so you can quickly find a story that resonates with a specific prospect's context. Using an outdated Google Drive version or a website link that hasn't been approved for external use creates risk. When in doubt, go to Highspot.", resource: { label: "Customer Stories Highspot Hub", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 2, type: "mc", lo: "LO2", text: "An AE drops a generic Amplitude customer case study PDF into an email before a discovery call with a VP of Product at a healthcare tech company. What's wrong with this approach?", options: ["Nothing — customer stories build credibility and should be shared early in the sales cycle to establish Amplitude's track record before the prospect begins comparing alternatives", "Customer stories should never be shared before discovery — they reveal Amplitude's positioning prematurely and give the prospect ammunition to prepare counter-objections for the evaluation", "A generic story doesn't apply Challenger Tailor. It must resonate with this persona (VP of Product) in this industry (healthcare tech) around a pain they've described. Use Highspot for industry-specific, persona-relevant stories.", "PDFs aren't tracked — use Highspot share links so you can see if they opened it, enabling you to gauge engagement levels and time follow-up based on actual content consumption data"], correct: 2, explanation: "Customer stories are most powerful when they're Tailored — the Challenger T in Teach-Tailor-Take Control. A generic story signals you haven't done your homework. The right story is industry-matched (healthcare), persona-matched (VP of Product's pain: roadmap validation, feature impact visibility), and use-case-matched to what the prospect has described as their challenge. Highspot's industry and use case filters exist precisely for this. Tracking views is a secondary benefit — the primary value is relevance.", resource: { label: "ICP: Personas & Industries Deck — How to Use Industry Content (Tailor to Persona)", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 3, type: "mc", lo: "LO3", text: "You're in an S3 Business & Technical Evaluation with a B2B SaaS prospect. Their champion is enthusiastic but hasn't been able to get their VP of Engineering (the Economic Buyer) engaged. Which use of a customer story best serves a Challenger objective here?", options: ["Send the VP of Engineering a direct email with 3 customer case studies — volume creates credibility and demonstrates breadth of customer success across different technical environments and scale requirements", "Enable your champion: find a story with an outcome that resonates with a VP of Engineering (shipped faster, trusted data) and coach them to share it internally. The story does the Teach inside the buying org.", "Save the customer story for the proposal stage — it's more impactful at S5 when the buyer is closer to decision and actively weighing the final shortlist against budget and implementation timeline", "Ask your champion to forward the generic product overview PDF to the VP of Engineering — the product overview covers more ground than a single story and gives the EB a comprehensive view of the platform"], correct: 1, explanation: "This is champion coaching through customer stories — a core Challenger application. Your champion can't always articulate Amplitude's value in Engineering language. A story featuring a VP of Engineering at a similar B2B SaaS company who said 'we can now ship the right features faster and trust our data' gives your champion a credible, peer-level narrative to take into their internal sell-through. You're equipping them to Teach the EB on your behalf. That's more effective than you emailing the EB directly — and it's exactly what the CEM S3 'Champion coaching sessions' activity is designed for.", resource: { label: "Customer Engagement Model — S3 Business & Technical Evaluation: Champion Coaching Sessions", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 4, type: "mc", lo: "LO1", text: "Amplitude's three core value drivers that customer stories and use cases are organized around are:", options: ["Analytics, Experimentation, and Activation — aligned with Amplitude's three core platform pillars, each representing a distinct product category and buyer journey stage", "Acquisition, Retention, and Monetization", "Product, Marketing, and Data personas — organized by the three primary buyer personas who champion analytics initiatives within customer organizations", "Grow, Optimize, and Scale — representing the three maturity stages of a customer's analytics journey, from initial adoption through full platform utilization"], correct: 1, explanation: "Amplitude's three core value drivers are Acquisition (getting users), Retention (keeping users), and Monetization (growing revenue from users). Industry-specific use case cheat sheets, customer stories, and value maps are all organized around these three drivers. When you pick a customer story, you're matching the value driver the prospect cares most about — a company struggling with retention churn needs a retention story, not an acquisition story.", resource: { label: "ICP: Personas & Industries Deck — Tying Industry Use Cases to Value (Acquisition/Retention/Monetization)", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 5, type: "tf", lo: "LO2", text: "True or False: You should lead with a customer story at the very beginning of an S1 Discovery call to establish Amplitude's credibility before asking any questions.", options: ["True", "False"], correct: 1, explanation: "Customer stories are tools for the Tailor phase of Challenger — not the opening move. Opening with a story before you know what the prospect cares about produces a generic pitch. The right sequence: Teach (open with a commercial insight that challenges their assumption), probe to understand their specific pain, then Tailor the story to exactly what they've told you they're struggling with. A story that lands perfectly in context is exponentially more powerful than a story that opens cold.", resource: { label: "ICP: Personas & Industries Deck — How to Use Industry Content for Prospecting", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 6, type: "mc", lo: "LO3", text: "A prospect says: 'We're not sure Amplitude can handle our scale — we have 500M monthly events.' What's the ideal response that uses a customer story?", options: ["Tell them that Amplitude handles billions of events per month and share the technical architecture documentation so their engineering team can review the infrastructure details and SLA guarantees directly", "Share a specific story from a similar-scale company in their industry — name the peer, cite comparable event volume, quote their Head of Data. Then offer to connect them directly.", "Assure them that scale isn't an issue and offer a POV so they can verify for themselves — letting the prospect test at their own volume removes the need to rely on another company's experience", "Ask them to clarify their exact use case before responding — the scale question depends heavily on event types, query complexity, and whether they need real-time or batch processing capabilities"], correct: 1, explanation: "Scale objections are handled best with social proof from a peer company at comparable scale. The most powerful version of a customer story in this context: specific company (well-known enough to resonate), specific scale (comparable to the prospect's), specific outcome quote from a technical stakeholder. If you can arrange a customer reference call, even better — peer-to-peer validation of scale credibility outperforms any Amplitude claim. Know your reference-ready customers in Highspot and your network well enough to deploy this quickly.", resource: { label: "Customer Stories Highspot Hub", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 7, type: "mc", lo: "LO1", text: "PODcast recordings are referenced as a resource for Day 12 Customer Stories. What is the primary purpose of these recordings for a new AE?", options: ["They're product demo recordings that show how Amplitude works in real customer environments, giving new AEs a library of pre-built demo flows they can reference before running their own customer presentations", "They're recordings of Pod teams (AE + CSM + SE) sharing real deal stories — win/loss lessons, customer moments, and field insights that help new AEs see what good looks like.", "They're customer testimonial videos for external use in prospect conversations — filmed and approved by marketing for sharing during evaluations and proposals to build social proof", "They're internal all-hands recordings where senior leadership discusses company strategy, product roadmap, and market positioning that inform how AEs should frame Amplitude in competitive deals"], correct: 1, explanation: "PODcast recordings feature Amplitude Pod teams sharing real deal stories — wins, losses, key moments, lessons learned. For new AEs, these recordings are a shortcut to institutional knowledge: how deals actually unfold, what customers really say, how the team navigates challenges together. They complement the formal curriculum with real-world texture that no slide deck can fully capture. Listening to a PODcast before a competitive deal or a renewal conversation gives you field-tested patterns, not just frameworks.", resource: { label: "Customer Stories Highspot Hub — PODcast Recordings", url: "https://amplitude.highspot.com/" } },
      { id: 8, type: "fill", lo: "LO1", text: "Amplitude's customer stories are organized in Highspot around three value drivers: Acquisition, Monetization, and ________.", correct: ["Retention", "retention"], placeholder: "third value driver...", explanation: "The three value drivers are Acquisition, Retention, and Monetization. Retention is often the most powerful value driver for Amplitude because it directly connects to the core product analytics use case: understanding why users drop off, what features drive long-term engagement, and how to build products that keep users coming back. When prospecting or preparing for discovery, know which value driver is most relevant to the prospect's current business priority — it determines which stories and use cases to lead with.", resource: { label: "ICP: Personas & Industries Deck — Tying Industry Use Cases to Value Drivers", url: "https://docs.google.com/presentation/d/1i6jAipawDy9ER5Bls-FFdXdr4hQA41XKw-wYqK5RttE/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "A prospect has given positive buying signals but their Legal team has flagged concerns about data privacy and GDPR compliance. Which type of customer story would be most effective in this situation?", options: ["A product analytics success story from a high-growth B2B SaaS company showing fast time-to-insight — demonstrating speed-to-value helps Legal see that the implementation risk is low and the compliance overhead is manageable", "A story from a regulated industry (healthcare or financial services) that addresses how they navigated data privacy, GDPR compliance, and governance with Amplitude.", "Any customer story — the buying signal matters more than the story type at this late stage, and any social proof will help move the deal forward regardless of industry or compliance specifics", "Skip the customer story and go straight to sharing Amplitude's SOC 2 certification and security documentation — Legal teams respond to formal compliance artifacts, not narrative customer stories"], correct: 1, explanation: "Legal and compliance objections require peer validation from companies in similarly regulated environments. A customer story from financial services (which must comply with strict data regulations) or healthcare (HIPAA considerations) that specifically speaks to governance, data privacy, and compliance builds credibility in exactly the domain where the objection lives. This is Challenger Tailor applied to legal risk: you're not defending Amplitude's security posture — you're showing that companies with higher compliance requirements have navigated this successfully.", resource: { label: "Customer Stories Highspot Hub — Financial Services & Healthcare Stories", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
      { id: 10, type: "mc", lo: "LO2", text: "You've found a perfect customer story in Highspot for your prospect — it's from a peer company, same industry, same use case, and features a quote from a VP of Product. How do you deploy it most effectively in the deal?", options: ["Send it immediately as a follow-up email — speed is important to maintain momentum, and getting the story in front of the prospect before the next meeting keeps Amplitude top of mind during their evaluation", "Reference it verbally first — frame it around what the prospect told you, then send the tracked Highspot link. Use it to deepen pain or validate value, not as a closing tool.", "Save it for the proposal stage — customer stories are most effective when the customer is actively making a decision and needs final reassurance before signing the contract", "Forward it to your champion and ask them to share it with stakeholders — your champion is better positioned to deliver it than you are, since peer-to-peer sharing carries more credibility than vendor-to-buyer"], correct: 1, explanation: "Deploying a customer story effectively requires context. Referencing it verbally first — framing it around what the prospect has told you — signals you've been listening and makes the story relevant rather than generic. The Highspot share link enables tracking, so you can see if they opened it and forwarded it to other stakeholders (a signal of internal interest). Using the story to deepen pain ('their VP of Product had the same problem you described — here's what it cost them') is more powerful than using it as a closing proof point. Timing, relevance, and delivery method all matter.", resource: { label: "Customer Stories Highspot Hub — Deploying Stories Effectively", url: "https://amplitude.highspot.com/spots/5f12a41df2c4af64a3d5ff68" } },
    ],
  },
  {
    id: "day13", day: "Day 13", title: "Contract Lifecycle Management", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "What is the CLM system used at Amplitude for contract management?", options: ["DocuSign CLM — DocuSign's contract management platform integrates natively with the e-signature workflow, keeping contracts and signatures in one unified system", "Ironclad", "Salesforce Contracts — the native Salesforce Contracts module provides built-in lifecycle tracking that automatically syncs with opportunity records and deal status", "Conga Composer — Conga's document generation and CLM suite is widely adopted across Salesforce-centric sales organizations for template-based contract creation"], correct: 1, explanation: "Ironclad is Amplitude's contract lifecycle management (CLM) system. It manages the end-to-end contract process from creation through archiving. For questions on process, post in #help-legal on Slack. For technical issues in Salesforce related to contracts, submit a ticket to business systems. The CLM Confluence page has step-by-step guides for everything related to customer agreements.", resource: { label: "CLM Slides — CLM: Ironclad", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 2, type: "match", lo: "LO1", text: "Match each agreement type to its purpose.", pairs: [{ term: "MSA (Master/Main Service Agreement)", match: "Governs the Amplitude Services for customers who have purchased a paid (at least $50K) subscription" }, { term: "NDA (Non-Disclosure Agreement)", match: "Protects Amplitude's confidential and proprietary information during pre-sales" }, { term: "DPA (Data Processing Addendum)", match: "Governs the processing of personal data in connection with a customer's use of Amplitude Services" }, { term: "BAA (Business Associate Addendum)", match: "Permits a customer to process certain personal health information (PHI) through Amplitude Services — required for healthcare customers" }], correct: 0, explanation: "Each agreement type has a specific purpose and timing in the contract lifecycle. NDAs appear in Pre-Sales. Order Forms and MSAs are central to Sales Negotiation. DPAs and BAAs are addenda that address specific data processing and compliance requirements. Knowing which agreement applies when prevents delays at the contract stage — especially for regulated industries (healthcare requiring BAA, EU customers requiring DPA with specific GDPR terms).", resource: { label: "CLM Slides — Most Common Agreement Types", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 3, type: "mc", lo: "LO1", text: "What is the minimum deal size that triggers an MSA requirement at Amplitude?", options: ["$25,000 — this lower threshold ensures even small deals receive proper legal coverage and standard commercial terms from the start of the relationship", "$50,000", "$100,000 — this higher threshold reduces legal overhead on mid-market deals and allows smaller customers to close faster on standard online terms", "$250,000 — MSAs are reserved for strategic and enterprise-tier engagements where the complexity of custom terms justifies dedicated legal review and negotiation"], correct: 1, explanation: "The MSA (Master Service Agreement) is required for customers who have purchased a paid subscription of at least $50K. Below this threshold, customers may operate on Amplitude's standard online terms without a negotiated MSA. This threshold matters for deal velocity: smaller deals can close faster without going through MSA negotiation, while deals at or above $50K should anticipate Legal's involvement in contract review.", resource: { label: "CLM Slides — MSA: Governs Customers with Paid Subscription (at least $50K)", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 4, type: "mc", lo: "LO2", text: "An AE is at S6 Negotiation. The customer's Legal team has sent back redlines on the Order Form. What's the correct process to handle these?", options: ["Reply directly to the customer's Legal team via email with Amplitude's counter-redlines — direct communication speeds up the review cycle and keeps the AE in control of the negotiation timeline", "Create a Salesforce case to engage Legal — all redline reviews go through the SFDC case process, not direct email threads", "Ask your FLM to review the redlines and approve any changes before sending to Legal — FLMs have authority to approve standard redline modifications within established commercial guardrails", "Handle simple redlines yourself and escalate only complex ones to Legal — experienced AEs can approve standard changes like payment terms and renewal notice periods without Legal involvement"], correct: 1, explanation: "All Legal engagement for customer agreements goes through the Salesforce case process. AEs should not negotiate redlines directly with customers via email — this creates version control issues, untracked commitments, and legal liability. Create a SFDC case, tag Legal (Joy Udom's team), and let Legal manage the redline review. For general process questions post in #help-legal. The CLM Confluence page has step-by-step guides for exactly this workflow.", resource: { label: "CLM Slides — Resources: Create a Salesforce Case for Customer Questions", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 5, type: "mc", lo: "LO3", text: "A prospect is in healthcare and wants to use Amplitude to track patient app engagement data that includes protected health information (PHI). Which additional agreement is required beyond the standard MSA and Order Form?", options: ["A DPA (Data Processing Addendum) — all data processing requires a DPA, and the standard DPA already covers the privacy requirements that healthcare organizations need for patient data handling", "An InfoSec Addendum — security review is required for healthcare customers, and the addendum documents the additional security controls and audit rights that regulated industries expect from SaaS vendors", "A BAA (Business Associate Addendum) — permits processing PHI through Amplitude's services, required for HIPAA compliance", "No additional agreements — the standard MSA covers all data types including PHI, since Amplitude's enterprise security posture and SOC 2 certification satisfy HIPAA's administrative safeguard requirements"], correct: 2, explanation: "A Business Associate Addendum (BAA) is required for healthcare customers who will process Personal Health Information (PHI) through Amplitude. This is a HIPAA compliance requirement — without a BAA, Amplitude cannot legally be used to process PHI. This should surface early in discovery with healthcare prospects: 'Will you be tracking any data that includes protected health information?' If yes, flag Legal early and factor BAA negotiation into the deal timeline. GA4's lack of HIPAA compliance is actually a competitive advantage for Amplitude in healthcare.", resource: { label: "CLM Slides — BAA: Permits Processing of PHI Through Amplitude Services", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: For DocuSign signature, the standard practice at Amplitude is that Amplitude countersigns the Order Form first, then sends to the customer to sign.", options: ["True", "False"], correct: 1, explanation: "Per the Deal Desk CPQ deck: 'Standard practice is Customer signs first and Amplitude countersigns.' This is standard commercial practice — the customer's signature commits them first, then Amplitude countersigns to execute the agreement. Deviating from this (having Amplitude sign first) creates operational complexity and risk. If a customer requests that Amplitude sign first, that requires a conversation with Legal and Deal Desk.", resource: { label: "Deal Desk + CPQ Slides — DocuSign Order Form Process (Customer Signs First)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 7, type: "mc", lo: "LO2", text: "Before sending an Order Form to a customer via DocuSign, you notice it doesn't have an Amplitude stamp on it. What should you do?", options: ["Send it anyway — the stamp is administrative and doesn't affect the legal validity of the document, since the DocuSign signature fields are what legally bind the parties regardless of internal review markings", "Add the stamp yourself by downloading the PDF and using a PDF editor — the stamp template is available on the CLM Confluence page and can be applied directly by the AE to avoid delays", "Stop and reach out to Deal Desk — an unstamped OF should never be sent. Standard OFs: stamp under signature block; custom/offline OFs: stamp in footer of every page.", "Ask your FLM to review the document and confirm it's acceptable to send — FLMs have the authority to approve order forms for sending when Deal Desk is unavailable or the deal timeline requires immediate action"], correct: 2, explanation: "Per the Deal Desk deck: 'If you don't see a stamp on the Order Form you are sending to the customer — STOP — and reach out to Deal Desk.' The Amplitude stamp on an Order Form is the official mark of authorization — it means Deal Desk has reviewed and approved the document. Sending an unstamped OF to a customer creates legal exposure and administrative chaos. Standard OFs: stamp under signature block. Custom/offline OFs: stamp in footer of every page.", resource: { label: "Deal Desk + CPQ Slides — Order Form Stamp (STOP if No Stamp)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "For process questions about Legal and contracts, AEs should post in the ________ Slack channel.", correct: ["#help-legal", "help-legal"], placeholder: "Slack channel...", explanation: "#help-legal is the Slack channel for process questions about Legal and contract management. For technical issues in Salesforce, submit a business systems ticket. For step-by-step guides on agreement types and processes, check the Confluence page. Using the right channel gets you to the right expert and creates an audit trail of the question and answer.", resource: { label: "CLM Slides — Resources (#help-legal)", url: "https://docs.google.com/presentation/d/1qlfiR7FE_tkMei8SNNktEAxv0YLausl_gBXxrEvTm54/edit" } },
      { id: 9, type: "mc", lo: "LO2", text: "A customer asks for a Future Purchase Option (FPO) to be shown on their Order Form. What's the correct way to add this in 2026 PPL?", options: ["Create an IronClad ticket with Legal to add a FPO Addendum to the Order Form — FPOs require legal language review and formal addendum processing through the CLM system before they can appear on the document", "Select the 'OF-Display FPO' checkbox on the Quote page in Salesforce — the self-serve way to display FPO on 2026 PPL Order Forms", "Open a Deal Desk case and ask them to add the language to the offline Order Form — FPO terms are non-standard and require Deal Desk to manually insert the approved language into the document", "FPOs are no longer available on 2026 PPL Order Forms — the 2026 pricing model eliminated FPOs in favor of simplified expansion pricing that doesn't require pre-negotiated future rates"], correct: 1, explanation: "For Future Purchase Options (FPO) on 2026 PPL, the correct self-serve path is to select the 'OF-Display FPO' checkbox on the Quote page in Salesforce. This is one of the key takeaways from the Deal Desk MindTickle training. Knowing this self-serve option saves a Deal Desk case and speeds up the deal. If you have questions about the FPO terms or need non-standard FPO language, that's when you create a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Key Takeaways: FPO Display (OF-Display FPO Checkbox)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 10, type: "mc", lo: "LO3", text: "You're closing a deal and the customer's procurement team says: 'We need to process payment through AWS Marketplace — can Amplitude accommodate that?' What's the correct response and process?", options: ["Decline — Amplitude doesn't support AWS Marketplace purchases, so the customer will need to process payment through standard invoicing via the Deal Desk-generated Order Form and DocuSign workflow", "Yes — open a Deal Desk case with the AWS Account ID, buyer name/email, and MSA status. Once the customer accepts the AWS Offer, move the Opportunity to S6.5.", "Yes, but only for deals under $50K — larger deals cannot be processed through AWS Marketplace due to the marketplace fee structure and the requirement for custom MSA terms on enterprise-tier contracts", "AWS Marketplace purchases bypass the standard order form process — no Deal Desk involvement needed, since AWS handles the commercial terms and billing relationship directly with the customer"], correct: 1, explanation: "AWS Marketplace is a supported purchase channel at Amplitude. The process: (1) open a Deal Desk case with the customer's AWS Account ID, buyer name/email, and MSA status, (2) Deal Desk creates the AWS Marketplace offer, (3) customer accepts the offer via AWS, (4) move Opportunity to Stage 6.5. The step-by-step guide is linked in the Deal Desk CPQ deck. AWS Marketplace deals still require proper opportunity hygiene and Deal Desk coordination — they don't bypass the standard process.", resource: { label: "Deal Desk + CPQ Slides — AWS Marketplace Process", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
    ],
  },
  {
    id: "day14", day: "Day 14", title: "Deal Desk & CPQ", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "What are the three stated missions of the Deal Desk team at Amplitude?", options: ["Quote generation, Order Form management, and Contract archiving — Deal Desk's primary function is operational document management, ensuring every quote and order form is accurately generated and properly stored", "Strategic & Trusted Advisors, Close Healthy Deals, and Drive Deal Velocity", "Pricing approval, Legal coordination, and CRM hygiene — Deal Desk sits at the intersection of commercial operations and legal compliance, ensuring pricing stays within guardrails and CRM data is accurate", "Revenue forecasting, Deal structuring, and Customer success handoffs — Deal Desk bridges the gap between sales execution and post-sale operations to ensure smooth revenue recognition and customer transitions"], correct: 1, explanation: "Per the Deal Desk deck, the three missions are: (1) Strategic & Trusted Advisors — coach and advise to scale commercial best practices, identify opportunities for Bigger Better Faster deals; (2) Close Healthy Deals — support optimal pricing and terms, partner cross-functionally, because a healthy land deal = better renewals; (3) Drive Deal Velocity — process improvement and enablement. Understanding Deal Desk as a strategic partner (not just a quoting service) changes how you engage with them — bring them in early on complex deals, not just at the quote stage.", resource: { label: "Deal Desk + CPQ Slides — How Can Deal Desk Help You? (3 Missions)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "How do you engage Deal Desk for support on a specific deal?", options: ["Post in the #help-salesops Slack channel and tag @DealDesk — Slack is the fastest way to reach Deal Desk for time-sensitive quoting questions during active negotiations", "Email the Deal Desk team distribution list with your request — email creates a paper trail and allows you to attach relevant documents like competitive quotes and customer term sheets", "From the Opportunity or Quote in SFDC: Cases → New → 'Deal Desk' record type → 'Deal Desk Support' → fill in Issue Type, Subject, and Description", "Create a Jira ticket and assign it to the Deal Desk team — Jira's project tracking ensures Deal Desk requests are prioritized alongside other operational work streams"], correct: 2, explanation: "The correct process to engage Deal Desk is: open a Salesforce case from the Opportunity or Quote → select 'Deal Desk' as record type → select 'Deal Desk Support' → fill in Issue Type, Subject, and Description. All follow-up communications happen via Chatter on that case — keep everything in Chatter so Deal Desk can track context. Slacking individual Deal Desk members or emailing outside SFDC creates fragmentation and delays. The more context you provide in the Description, the faster Deal Desk can act.", resource: { label: "Deal Desk + CPQ Slides — How & When to Engage with Deal Desk (SFDC Case Process)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "You're building a quote in CPQ and receive an error: 'Please add the following required implementation SKU to save this quote: Amplitude Essential Platform Implementation.' What does this mean and what do you do?", options: ["It's a system bug — submit a ticket to the business systems team, since CPQ errors are typically configuration issues that need to be resolved by the admin team before you can proceed", "The customer has opted out of implementation services — update the quote to remove the implementation requirement, which the customer confirmed during the S3 evaluation that they don't need", "CPQ is enforcing the mandatory implementation attach. Navigate to the wrench icon on the first line item and select the correct implementation SKU by ARR tier.", "Click 'Ignore' on the warning and proceed — implementation is optional for some deal types, and the CPQ system generates this alert by default regardless of whether the customer qualifies for a waiver"], correct: 2, explanation: "This is the CPQ system enforcing the mandatory implementation mandate for 2026 PPL. To resolve it: navigate to the wrench icon on the first line item (not the 'Add Products' button at the top) and select the correct implementation SKU. The wrench icon keeps all products within the bundle. The 'Add Products' button at the top is only for the One Time Discount SKU. If you believe the deal qualifies for an implementation waiver, that requires Deal Desk + CRO approval — you can't simply dismiss the error.", resource: { label: "Deal Desk + CPQ Slides — Product Configurator: Required Implementation SKU Error", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 4, type: "mc", lo: "LO1", text: "What does FPO stand for, and when is it relevant in a deal?", options: ["Final Purchase Option — used when the customer is ready to sign, indicating they've completed their evaluation and are prepared to execute the agreement at the quoted terms", "Future Purchase Option — shows what products and pricing the customer can add during the term without new negotiation", "Fixed Price Override — used when the AE needs to hold pricing from a previous quote, ensuring rate consistency when a deal spans multiple approval cycles or fiscal quarters", "Finance Pre-Approval Option — used when the deal requires executive sign-off before quoting, ensuring commercial terms are approved by Finance leadership before being presented to the customer"], correct: 1, explanation: "FPO stands for Future Purchase Option. It appears on the Order Form and shows what products the customer can add later in their contract term at pre-agreed pricing — without requiring a full renegotiation. FPOs are a deal acceleration tool: they allow customers to feel confident in their initial purchase while having a clear path to expand. To add an FPO to a 2026 PPL Order Form, select the 'OF-Display FPO' checkbox on the Quote page. For non-standard FPO terms, open a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Amplitude Acronyms (FPO = Future Purchase Option)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 5, type: "match", lo: "LO1", text: "Match each CPQ acronym to its full meaning.", pairs: [{ term: "ARR", match: "Annual Recurring Revenue — the annualized value of subscription contracts" }, { term: "TCV", match: "Total Contract Value — the full value of the contract across all years" }, { term: "CPQ", match: "Configure-Price-Quote — the Salesforce quoting system used to build and generate quotes" }, { term: "FPO", match: "Future Purchase Option — pre-agreed pricing for products the customer may add during the contract term" }], correct: 0, explanation: "These are the core commercial acronyms at Amplitude. ARR is the primary revenue metric — it's what you're measured on, what renewals are tracked by, and what forecasting is based on. TCV is useful for multi-year deal comparisons. CPQ is the Salesforce quoting system — everything runs through it. FPOs appear on Order Forms when customers want the ability to expand without renegotiating commercial terms. Knowing these cold prevents embarrassing pauses in deal conversations.", resource: { label: "Deal Desk + CPQ Slides — Amplitude Acronyms Table", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 6, type: "mc", lo: "LO2", text: "You're building an amendment quote for an existing customer who wants to add Session Replay. What's a critical thing to check before saving the quote?", options: ["Verify the customer's billing contact is up to date in Salesforce — stale billing contacts cause invoice delivery failures and payment delays that can hold up contract activation and revenue recognition", "Check for existing POT add-on SKUs. If present and you're adding EV/MTUs, include existing POTs so they scale with the volume increase. New add-on? Just add as additional product.", "Make sure the quote expiration date is set to at least 30 days out — shorter windows pressure the customer and often result in expired quotes that require a full re-approval cycle through Deal Desk", "Confirm with your FLM that the discount level is within guidelines before building the amendment — FLM pre-approval prevents the quote from being rejected during the Deal Desk review and saves a round-trip"], correct: 1, explanation: "Amendment quoting has a specific nuance with POT SKUs: if the existing contract already has POT add-ons (like Guides & Surveys) and you're adding more EV/MTUs in the amendment, you must include those existing POT SKUs so they reprice correctly with the new volume. If the POT add-on (SR in this case) is brand new to the contract, just add it as an additional product. Getting this wrong means the quote won't correctly price the add-ons at the new volume — a Deal Desk rework and potential deal delay. Also: the Percent Discount field doesn't work on amendments — use Target Net Total instead.", resource: { label: "Deal Desk + CPQ Slides — Amendment Quotes: POT SKUs Key Points to Remember", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 7, type: "tf", lo: "LO1", text: "True or False: Selling above the Guided Selling Price (but below the List Price) requires Deal Desk and executive approval.", options: ["True", "False"], correct: 1, explanation: "The CPQ shows the Guided Selling Price in the Regular Total column — this is the recommended price based on market research and historical transaction data. You can sell higher than Guided (up to List) without special approval. Selling above List requires VP approval (routed through CPQ automatically). Selling above list is generally not recommended: 'Selling above list rates significantly increases the probability of customer churn or a competitor offering a better deal.' The Guided Price is designed to help you win — use it as your default.", resource: { label: "Deal Desk + CPQ Slides — Simplified Pricing: Guided Price vs List Rate", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "In the 2026 PPL CPQ Quote Line Editor, Implementation and PSP discounts can only be edited at the ________ level.", correct: ["line", "line level", "individual line", "individual line level"], placeholder: "which level...", explanation: "Implementation, Services, and PSP SKUs can only be discounted at the line level in the CPQ QLE — they are NOT included in the Target Net Total calculation that applies to subscription products. This means you can't use Target Net Total to price your implementation SKUs — you must manually set the discount on each PS line item individually. Missing this causes quoting errors and delays. For any non-standard PS quoting (custom SOWs, implementation waivers), open a Deal Desk case.", resource: { label: "Deal Desk + CPQ Slides — Quote Nuances: Implementation/PSP Edited at Line Level Only", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "An AE submits a quote for approval and it gets flagged: 'Business Case Justification incomplete.' What does a good Business Case include?", options: ["A summary of the customer's pain points and how Amplitude solves them — connecting the business case to value drivers helps approvers understand why the deal structure is justified by the customer's specific needs", "The gives/gets, which approvals are triggered and why, a commercial summary (CPM/discount/ARR/payment terms), and what changed since the last approval round.", "The MEDDPICC qualification notes for the opportunity — giving approvers the full qualification picture ensures they can assess deal risk and validate that the forecast category matches the evidence in SFDC", "A comparison of this deal's pricing to similar deals in the same industry — benchmarking against comparable transactions gives approvers confidence that the pricing structure is competitive and defensible"], correct: 1, explanation: "Per the Deal Desk deck, a good Business Case includes: (1) Gives/Gets — what is Amplitude conceding and what is the customer committing to in return? (2) Summary of asks — what approvals are being triggered? Touch on each ask individually. (3) Commercial summary — CPM (if EV), discount level, ARR increase/decrease, payment terms. (4) If re-routing through approvals — explain what changed from the last round. A vague Business Case means Deal Desk has to come back for more information — slowing down the approval and potentially the deal close.", resource: { label: "Deal Desk + CPQ Slides — What Does a Good Business Case Look Like?", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "When should you engage Deal Desk early in a deal — before you're ready to build a quote?", options: ["Never — Deal Desk only needs to be involved at the quoting stage, since their primary value is in accurate quote generation and order form production rather than deal strategy", "Only when the deal is over $500K ARR — below that threshold, standard pricing and terms apply and AEs have sufficient authority to structure deals within established commercial guardrails", "Any time you have a complex structure (ramps, multi-year, partners, non-standard terms, aggressive discounts, or waiver requests) — Deal Desk is a strategic advisor. Early alignment prevents approval surprises.", "Whenever your FLM asks you to — otherwise handle deal structure on your own, since experienced AEs should be able to navigate standard commercial terms without additional support"], correct: 2, explanation: "Deal Desk's stated mission includes being Strategic & Trusted Advisors who identify opportunities for Bigger Better Faster deals. Bringing Deal Desk in early on complex structures — ramps, multi-year, partner sub-co situations, aggressive pricing requests — means they can advise on the optimal structure before you've committed to a direction with the customer. Showing up with a half-built complex deal at the approval stage creates delays and structural fixes that slow velocity. The right time to engage Deal Desk on complex deals is at deal strategy, not at deal signing.", resource: { label: "Deal Desk + CPQ Slides — Strategic & Trusted Advisors (Engage Early on Complex Deals)", url: "https://docs.google.com/presentation/d/1C6iLzRnoEpi0W-0--79GHUlaA9CYxgo3ENujCabfRDk/edit" } },
    ],
  },
  {
    id: "day15", day: "Day 15", title: "Leveraging Solution Engineers & Professional Services", week: "Week 4",
    questions: [
      { id: 1, type: "mc", lo: "LO1", text: "At which CEM stages are Solution Engineers (SEs) actively involved in a new business deal?", options: ["S0 through S7 — SEs are involved at every stage of the deal cycle, providing continuous technical support from initial outreach through contract signing and post-sale handoff", "S1 and S2 only — SEs run discovery and qualification, then hand off to the AE for the business evaluation and proposal stages where commercial skills take priority over technical depth", "S2 (Qualification), S3 (Business & Technical Evaluation), S4 (Proof of Value), and S5 (Proposal) — not at S0 or S1 unless consulted", "S4 only — SEs are exclusively POC resources, deployed only when a formal proof of value is required to advance the deal past the technical validation gate"], correct: 2, explanation: "Per the SE Partnership slides, SEs are actively involved at S2 (Qualify/Justify), S3 (Business & Technical Evaluation), S4 (Proof of Value/POC), and S5 (Proposal — consulted if technical value is still in play). At S0 and S1, the SE is consulted only if technical criteria emerge. Understanding this prevents two common mistakes: bringing in the SE too early (before there's a qualified opportunity) or too late (after the technical win window has closed).", resource: { label: "Leveraging SEs Deck — Where Are SEs Involved? (S2, S3, S4, S5)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 2, type: "mc", lo: "LO1", text: "You need SE support on an active qualified opportunity. What are the two ways to engage an SE?", options: ["Email the SE directly or create a Zendesk ticket — Zendesk's ticketing system provides structured tracking and SLA management for SE engagements across the sales organization", "Informal: DM, #salesengineering, or ask for advice. Formal: file an SC request in SFDC; SE triage within 24 hours if required info is included.", "Only through your FLM — AEs should not contact SEs directly without manager approval, since FLMs coordinate SE capacity across the team and ensure fair allocation of limited technical resources", "Post in #help-salesops for triage, then the SE manager assigns the right SE to the deal — centralized triage ensures the SE with the best domain expertise and availability is matched to each opportunity"], correct: 1, explanation: "Two engagement paths: Informal — DM, #salesengineering, or ask for lightweight help on discovery prep, account prioritization, or early qualification questions. Formal — file a formal SC request in Salesforce for active opportunities requiring SE involvement. The formal request is triaged within 24 hours if you include the required information. Pro tip: set up a prep session at least one day before any customer meeting involving the SE — share notes in advance, come ready to discuss deal state, gaps, ideal outcomes, and roles & responsibilities.", resource: { label: "Leveraging SEs Deck — How to Request an SE (Informal vs Formal SC Request)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 3, type: "mc", lo: "LO2", text: "A prospect says 'We want a POC' at the S2 stage. Before committing the SE's time, what's the right first question to ask?", options: ["What's your timeline for the evaluation? — understanding the prospect's decision timeline helps you scope the right evaluation type and align SE resources to meet their deadline", "What does a POC mean to you? — 'POC' spans from a 30-minute custom demo (low effort, no plan needed) to a full End User Access POC with real data (high effort, plan required). Clarifying determines the right type.", "How many users will participate in the POC? — the number of participants drives the logistics planning and determines whether you need a dedicated demo environment or can use the standard sandbox", "Do you have technical resources available to support the implementation? — understanding the prospect's technical capacity helps scope the evaluation correctly and set realistic timelines for data ingestion and validation"], correct: 1, explanation: "Per the SE Partnership deck, 'POC' is ambiguous and overloaded. The evaluation types range widely: Custom Demo (low effort, no plan needed), Hands-On Workshop (low effort), Demo Account Access (low effort), Technical Validation (medium, requires Evaluation Plan), Session Replay POC (medium, requires plan), End User Access POC (high, requires plan, only for opps >$75K), and Experiment POC (high, requires plan). Jumping to a high-effort POC when a custom demo would win the deal wastes SE time and creates unnecessary risk. Clarify before committing.", resource: { label: "Leveraging SEs Deck — POC Qualification: Types of Evaluation", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 4, type: "match", lo: "LO1", text: "Match each evaluation type to its time investment and whether an Evaluation Plan is required.", pairs: [{ term: "Custom Demo", match: "Low time investment — SE builds a tailored demo based on customer use cases. No Evaluation Plan required." }, { term: "Technical Validation", match: "Medium time investment — customer validates their data structure, SDKs, and integrations. Evaluation Plan required." }, { term: "End User Access POC", match: "High time investment — customer's end users access real data in Amplitude. Evaluation Plan required. Only for opps >$75K." }, { term: "Experiment POC", match: "High time investment — technically validates A/B test implementation. Evaluation Plan required." }], correct: 0, explanation: "Evaluation type selection is a deal strategy decision, not a default response to every 'we want a POC' request. Custom Demos and Hands-On Workshops are the most efficient path to technical validation for most deals. High-effort evaluations (End User Access POC, Experiment POC) should only be run when the deal size and qualification level justify the investment — and they always require an Evaluation Plan with agreed success criteria. Without a plan, a POC drifts and rarely produces a clear win.", resource: { label: "Leveraging SEs Deck — Types of Evaluation Table (Time Investment & Evaluation Plan)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 5, type: "mc", lo: "LO2", text: "An AE schedules an SE for a customer meeting but doesn't share any context until 10 minutes before the call. What's wrong with this approach and what should happen instead?", options: ["Nothing — SEs are experienced enough to handle any meeting without preparation, and their deep product knowledge allows them to adapt to any customer scenario in real time", "Send notes at least one day before and schedule a 15–30 min prep session: transfer info, identify goals, spot gaps, define roles, finalize the plan. No alignment = wasted expertise.", "The AE should send the notes via Slack immediately before the call — as long as the SE reviews them before starting, the prep is sufficient for a productive customer interaction", "The SE should reschedule the meeting if they haven't received adequate preparation materials — going in unprepared creates more damage to the deal than a short delay for proper planning"], correct: 1, explanation: "Effective AE-SE partnership requires preparation — not improvisation. The SE Partnership deck specifies: 15–30 minute prep session at least one day before the customer meeting. The prep covers: brief review of prior call notes and account plan, identifying the goal and outcome, spotting information gaps, agreeing on which gaps to fill in the next touchpoint, identifying additional discovery and trap-setting questions, defining roles & responsibilities, and finalizing the meeting plan. A well-prepped SE operates as a co-pilot, not a presenter-for-hire.", resource: { label: "Leveraging SEs Deck — Ideal Prep Session (15–30 Mins, at Least 1 Day Before)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 6, type: "tf", lo: "LO1", text: "True or False: An End User Access POC — where the customer's end users access their real data in Amplitude — is available for all qualified opportunities regardless of deal size.", options: ["True", "False"], correct: 1, explanation: "End User Access POCs require significant SE time and internal resources — they're reserved for opportunities over $75K. Below that threshold, customers can access the demo environment at analytics.amplitude.com. This threshold exists to protect SE capacity and ensure high-effort evaluations are attached to deals that can justify the investment. If a <$75K opportunity is requesting an End User Access POC, have the strategic conversation about deal size first.", resource: { label: "Leveraging SEs Deck — POC Qualification: End User Access POC (Opps >$75K Only)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 7, type: "mc", lo: "LO3", text: "You're at S3 Business & Technical Evaluation. Your SE is leading the technical discovery and custom demo. What is the AE's primary role during this stage?", options: ["Let the SE run the calls — the AE's job during S3 is to stay silent, avoid interrupting the technical conversation, and only re-engage when the SE flags a commercial question that requires AE input", "Lead the commercial thread — Evaluation Plan, Champion coaching, BVA, MAP updates, EB engagement, stakeholder alignment — while the SE owns the Technical Win path", "Focus entirely on pricing negotiations and commercial terms while the SE independently handles all technical discovery, demo delivery, and evaluation plan design without AE coordination", "Create the SFDC opportunity, update mandatory S3 fields, and ensure all administrative CRM hygiene is completed — administrative work is the AE's primary S3 responsibility above all else"], correct: 1, explanation: "Per the CEM S3 AE responsibilities: build and align on Evaluation Plan with SE, lead Champion coaching sessions, drive BVA and success story delivery, update MAP with shared evaluation dates, manage EB engagement and stakeholder alignment, internal check-in with FLM, update SFDC mandatory S3 fields, and align with partner if co-sell. The SE is accountable for the Technical Win Path — custom demo, technical use case deep-dive, evaluation plan design. Both must be running in parallel. An AE who disappears during S3 and lets the SE 'run the deal' loses control of the commercial thread.", resource: { label: "Customer Engagement Model — S3 Business & Technical Evaluation: AE Responsibilities", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
      { id: 8, type: "fill", lo: "LO1", text: "The Slack channel where you can find and connect with the Solutions Engineering team is ________.", correct: ["#salesengineering", "#solutions-engineering", "salesengineering", "solutions-engineering"], placeholder: "channel name...", explanation: "The SE team's Slack channel is #salesengineering (also referenced as #solutions-engineering). Use it for informal questions, early-stage discovery prep, competitive intel, or to flag an account you want SE perspective on before filing a formal request. The SE team is a shared resource — the informal channel is for lightweight questions, while formal SFDC requests are for active opportunities requiring dedicated SE engagement.", resource: { label: "Leveraging SEs Deck — Where to Find Us (#salesengineering)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 9, type: "mc", lo: "LO3", text: "A prospect at S3 says: 'We're a Mixpanel customer today — before we go further, we need to see a head-to-head comparison with your product.' How should the AE and SE approach this?", options: ["Decline the head-to-head — competitive bake-offs rarely produce clear winners, often confuse the prospect with feature-level noise, and should be avoided in favor of a narrative-driven approach that keeps the conversation strategic", "Agree immediately and schedule a bake-off demo for the following week — showing confidence signals conviction in the product, and speed-to-demo prevents the prospect from setting evaluation criteria without Amplitude's input", "Treat it as a Trap-Setting moment — align with the SE on evaluation criteria shaped around Amplitude's differentiators before committing to the bake-off format", "Redirect to a POC instead — propose loading the prospect's own data into Amplitude so they can evaluate real workflows, which is far more compelling than a side-by-side feature comparison on synthetic scenarios"], correct: 2, explanation: "Competitive evaluations are won or lost before they start — in how the evaluation criteria are defined. The AE-SE prep session for a Mixpanel bake-off should identify: what criteria does the prospect currently have? Are those criteria shaped around Mixpanel's strengths? Use Trap-Setting questions to surface Amplitude's differentiators as requirements: 'How important is it that your marketing and growth teams can self-serve analytics without going through an analyst?' That's a capability Mixpanel struggles with and Amplitude excels at. Win the criteria; win the bake-off.", resource: { label: "Leveraging SEs Deck — How to Have an Effective Partnership (Trap-Setting Questions)", url: "https://docs.google.com/presentation/d/1kDmK2l_Ahv01UlrBDSWoPqhtT70dQTcBT2GJ6PoSZzA/edit" } },
      { id: 10, type: "mc", lo: "LO2", text: "After a successful S4 POC, the SE documents the Technical Win. What specifically must happen at S4 exit, and who owns each item?", options: ["The SE sends a POC summary email to the customer recapping use cases validated, technical risks resolved, and next steps — that email constitutes the official Technical Win documentation and no SFDC update is required beyond attaching it", "Technical Win confirmed and SFDC-documented (SE), Path to Production with Architecture Diagram (SE), Services forecasted (AE), Champion ready for internal business case (AE), Deployment plan drafted (TSM), Security/Legal initiated (AE), SFDC updated (shared)", "The AE submits the formal proposal and pricing — once the proposal is sent the deal automatically advances to S5, and the Technical Win documentation is generated by SFDC based on the stage transition without any manual SE input", "The customer signs a formal evaluation completion form provided by the SE — that signed document is the official Technical Win confirmation and is uploaded to SFDC as the stage-gate artifact"], correct: 1, explanation: "S4 exit requires multiple owners completing specific items: (1) Technical Win confirmed by Champion/technical stakeholders and documented — SE owns this. (2) Path to Production with Architecture Diagram documented — SE. (3) Services attached and forecasted — AE. (4) Champion ready to support internal business case — AE. (5) Deployment plan drafted (TSM leads for deals >$100K). (6) Security/Legal reviews initiated — AE. (7) SFDC updated — shared. Missing any of these means you're not actually at S4 exit — you're at risk of a deal that slips because the internal business case hasn't been built or security review creates a last-minute surprise.", resource: { label: "Customer Engagement Model — S4 Proof of Value Exit Criteria", url: "https://docs.google.com/document/d/1VxMWNbIWWEtJwuhNibKHUCsbOsCQqVFcin8vrZkeKZw/edit" } },
    ],
  },
];
